-- C0675 · Migración simple (schema versioning) (Intermedio, Base de datos)
-- SAP ASE (Sybase): tabla de migraciones + v1 (conceptual)
IF NOT EXISTS (SELECT 1 FROM sysobjects WHERE name = 'schema_migrations' AND type = 'U')
BEGIN
  CREATE TABLE schema_migrations (
    version VARCHAR(50) NOT NULL PRIMARY KEY,
    applied_at DATETIME NOT NULL DEFAULT GETDATE()
  );
END;

IF NOT EXISTS (SELECT 1 FROM sysobjects WHERE name = 'customers' AND type = 'U')
BEGIN
  CREATE TABLE customers (
    id NUMERIC(18,0) IDENTITY PRIMARY KEY,
    name VARCHAR(200) NOT NULL,
    email VARCHAR(200) NULL
  );
END;

IF NOT EXISTS (SELECT 1 FROM schema_migrations WHERE version = 'v1')
  INSERT INTO schema_migrations(version) VALUES ('v1');
